#nullable enable // autogenerated  

using MVZ2.GameContent.Detections;
using MVZ2.GameContent.Effects;
using MVZ2.GameContent.Entities;
using MVZ2.Vanilla.Audios;
using MVZ2.Vanilla.Contraptions;
using MVZ2.Vanilla.Detections;
using MVZ2.Vanilla.Entities;
using MVZ2Logic.Entities;
using MVZ2.Vanilla.Properties;
using PVZEngine;
using PVZEngine.Definitions;
using PVZEngine.Entities;
using Tools;
using UnityEngine;

namespace MVZ2.GameContent.Contraptions
{
    [AutoEntityBehaviourDefinition(VanillaContraptionNames.amethystPylon)]
    // 基类由 AIEntityBehaviour 改为 ContraptionBehaviour，以获得 Trigger(调档) 与 Evoke(大招) 机制  
    public class AmethystPylon : ContraptionBehaviour
    {
        public AmethystPylon(string nsp, string name) : base(nsp, name)
        {
            detector = new AmethystPylonDetector();
        }
        public override void Init(Entity entity)
        {
            base.Init(entity);
            SetStateTimer(entity, TimerHelper.NewSecondTimer(ATTACK_COOLDOWN_SECONDS));
            SetDriverGear(entity, 0);   // 初始驱动档位为 0  
        }

        // ===== 大招(Master Spark)：从原 AmethystPylon_Evoke 迁移过来 =====  
        // ContraptionBehaviour.Evoke 会调用 OnEvoke，因此这里 override OnEvoke 即可  
        protected override void OnEvoke(Entity entity)
        {
            base.OnEvoke(entity);
            var sourcePosition = GetLaserPosition(entity);
            var param = entity.GetSpawnParams();
            param.SetProperty(EngineEntityProps.FLIP_X, entity.IsFacingLeft());

            entity.Spawn(VanillaEffectID.masterSpark, sourcePosition, param)?.Let(l =>
            {
                SetMasterSparkID(entity, new EntityID(l));
                l.SetParent(entity);
                entity.SetEvoked(true);
            });
        }

        // ===== 调档(Trigger)：每次触发把驱动档位 +1，在 0~7 之间循环 =====  
        protected override void OnTrigger(Entity entity)
        {
            base.OnTrigger(entity);
            int gear = (GetDriverGear(entity) + 1) % 8;
            SetDriverGear(entity, gear);
        }
        // 大招期间禁止调档，避免与 Master Spark 状态冲突  
        public override bool CanTrigger(Entity entity)
        {
            if (entity.IsEvoked())
                return false;
            return base.CanTrigger(entity);
        }

        protected override void UpdateAI(Entity entity)
        {
            base.UpdateAI(entity);
            if (entity.IsEvoked())
            {
                SetCrystalAlpha(entity, 1);
                var masterSparkID = GetMasterSparkID(entity);
                var masterSpark = masterSparkID?.GetEntity(entity.Level);
                if (!masterSpark.ExistsAndAlive() || MasterSpark.IsShrinking(masterSpark))
                {
                    SetMasterSparkID(entity, null);
                    SetCrystalAlpha(entity, 0);
                    entity.SetEvoked(false);
                    entity.ShortCircuit(Ticks.FromSeconds(EVOCATION_DISABLE_SECONDS), new EntitySourceReference(entity));
                    entity.PlaySound(VanillaSoundID.powerOff);
                }
                else
                {
                    var sourcePosition = GetLaserPosition(entity);
                    masterSpark.Position = sourcePosition;
                    masterSpark.SetFlipX(entity.IsFacingLeft());
                    masterSpark.SetFaction(entity.GetFaction());
                }
            }
            else
            {
                switch (entity.State)
                {
                    case STATE_IDLE:
                        UpdateStateIdle(entity);
                        break;

                    case STATE_ATTACK:
                        UpdateStateAttack(entity);
                        break;
                }
            }
        }
        protected override void UpdateLogic(Entity entity)
        {
            base.UpdateLogic(entity);
            var crystalAlpha = 0f;
            if (!entity.IsAIFrozen())
            {
                crystalAlpha = GetCrystalAlpha(entity);
            }
            entity.SetAnimationFloat("CrystalAlpha", crystalAlpha);
            entity.SetAnimationBool("Disabled", entity.IsAIFrozen());

            // ===== 实时计算"当前能发出的光等级"，用于水晶塔贴图颜色 =====  
            // 与攻击时的快照用同一公式：outputLevel = (∑入射等级 + 驱动档位) % 8  
            // 每帧更新，使贴图随入射光/档位变化实时反映"现在会发出什么颜色的光"  
            int incidentSum = AmethystPylon_Lit.GetIncidentSum(entity);
            int gear = GetDriverGear(entity);
            int currentLevel = (((incidentSum + gear) % 8) + 8) % 8;
            entity.SetModelProperty("OutputLevel", currentLevel);
        }
        private void UpdateStateIdle(Entity entity)
        {
            var timer = GetStateTimer(entity);
            if (timer.RunToExpiredAndNotNull(entity.GetAttackSpeed()))
            {
                if (detector.DetectExists(entity))
                {
                    entity.State = STATE_ATTACK;
                    timer.ResetSeconds(ATTACK_CHARGE_SECONDS);
                    entity.PlaySound(VanillaSoundID.boltCharge, volume: 0.5f);
                }
                else
                {
                    timer.SetSeconds(ATTACK_RECHECK_SECONDS);
                }
            }
            SetCrystalAlpha(entity, Mathf.Clamp01(GetCrystalAlpha(entity) - 0.05f));
        }
        private void UpdateStateAttack(Entity entity)
        {
            var timer = GetStateTimer(entity);
            if (timer.RunToExpiredAndNotNull(entity.GetAttackSpeed()))
            {
                if (detector.DetectExists(entity))
                {
                    Attack(entity);
                }
                timer.ResetSeconds(ATTACK_COOLDOWN_SECONDS);
                entity.State = STATE_IDLE;
            }
            SetCrystalAlpha(entity, Mathf.Clamp01(GetCrystalAlpha(entity) + 0.1f));
        }
        public static void Attack(Entity entity)
        {
            var sourcePosition = GetLaserPosition(entity);
            var laserScale = GetLaserScale(entity);

            // 攻击瞬间锁定入射光快照，计算输出等级 outputLevel = (∑入射 + gear) % 8  
            int incidentSum = AmethystPylon_Lit.GetIncidentSum(entity);
            int gear = GetDriverGear(entity);
            int outputLevel = (((incidentSum + gear) % 8) + 8) % 8;
            entity.SetModelProperty("OutputLevel", outputLevel);

            var param = entity.GetSpawnParams();
            param.SetProperty(VanillaEntityProps.DAMAGE, entity.GetDamage());
            param.SetProperty(EngineEntityProps.FLIP_X, entity.IsFacingLeft());
            param.SetProperty(EngineEntityProps.DISPLAY_SCALE, laserScale);
            param.SetProperty(EngineEntityProps.SCALE, laserScale);
            // 把输出等级传给激光，供其对命中的幽灵/怨灵施加对应颜色的发光 buff  
            param.SetProperty(LogicEntityProps.LIGHT_LEVEL, outputLevel);   // 必须在 param 声明之后、Spawn 之前  

            entity.Spawn(VanillaEffectID.amethystPylonLaser, sourcePosition, param);
        }
        public static Vector3 GetLaserPosition(Entity entity)
        {
            var laserScale = GetLaserScale(entity);
            var offset = entity.GetShotOffset();
            offset.x *= entity.GetFacingX();
            offset.y += (laserScale.y - 1) * Y_OFFSET_PER_LASER_SCALE;
            return entity.Position + offset;
        }

        // ===== 八色光谱：等级 -> 颜色。0白 1红 2橙 3黄 4绿 5青 6蓝 7紫 =====  
        public static Color GetSpectrumColor(int level)
        {
            switch (level)
            {
                case 0: return Color.white;                 // 白  
                case 1: return new Color(1f, 0f, 0f);       // 红  
                case 2: return new Color(1f, 0.5f, 0f);     // 橙  
                case 3: return new Color(1f, 1f, 0f);       // 黄  
                case 4: return new Color(0f, 1f, 0f);       // 绿  
                case 5: return new Color(0f, 1f, 1f);       // 青  
                case 6: return new Color(0f, 0f, 1f);       // 蓝  
                case 7: return new Color(0.55f, 0f, 1f);    // 紫  
                default: return Color.white;
            }
        }

        public static EntityID? GetMasterSparkID(Entity entity) => entity.GetBehaviourField<EntityID>(PROP_MASTER_SPARK_ID);
        public static void SetMasterSparkID(Entity entity, EntityID? timer) => entity.SetBehaviourField(PROP_MASTER_SPARK_ID, timer);
        public static FrameTimer? GetStateTimer(Entity entity) => entity.GetBehaviourField<FrameTimer>(PROP_STATE_TIMER);
        public static void SetStateTimer(Entity entity, FrameTimer? timer) => entity.SetBehaviourField(PROP_STATE_TIMER, timer);
        public static float GetCrystalAlpha(Entity entity) => entity.GetBehaviourField<float>(PROP_CRYSTAL_ALPHA);
        public static void SetCrystalAlpha(Entity entity, float value) => entity.SetBehaviourField(PROP_CRYSTAL_ALPHA, value);
        // 驱动档位(0~7)：behaviour field 供 C# 逻辑读取，同时写 model 属性供贴图切换  
        public static int GetDriverGear(Entity entity) => entity.GetBehaviourField<int>(PROP_DRIVER_GEAR);
        public static void SetDriverGear(Entity entity, int value)
        {
            entity.SetBehaviourField(PROP_DRIVER_GEAR, value);
            entity.SetModelProperty("DriverGear", value);
        }
        public static Vector3 GetLaserScale(Entity entity) => Mathf.Clamp(entity.GetDamage() / LASER_DAMAGE_SCALE_1, LASER_SCALE_MIN, LASER_SCALE_MAX) * Vector3.one;

        public const float ATTACK_COOLDOWN_SECONDS = 65 / 30f;
        public const float ATTACK_CHARGE_SECONDS = 25 / 30f;
        public const float ATTACK_RECHECK_SECONDS = 7 / 30f;
        public const float EVOCATION_DISABLE_SECONDS = 30f;
        public const float LASER_DAMAGE_SCALE_1 = 20f;
        public const float LASER_SCALE_MIN = 0.5f;
        public const float LASER_SCALE_MAX = 2.5f;
        public const float Y_OFFSET_PER_LASER_SCALE = -7f;
        public const int STATE_IDLE = VanillaContraptionStates.IDLE;
        public const int STATE_ATTACK = VanillaContraptionStates.AMETHYST_PYLON_ATTACK;
        public static readonly VanillaEntityPropertyMeta<EntityID> PROP_MASTER_SPARK_ID = new VanillaEntityPropertyMeta<EntityID>("master_spark_id");
        public static readonly VanillaEntityPropertyMeta<FrameTimer> PROP_STATE_TIMER = new VanillaEntityPropertyMeta<FrameTimer>("state_timer");
        public static readonly VanillaEntityPropertyMeta<float> PROP_CRYSTAL_ALPHA = new VanillaEntityPropertyMeta<float>("crystal_alpha");
        public static readonly VanillaEntityPropertyMeta<int> PROP_DRIVER_GEAR = new VanillaEntityPropertyMeta<int>("driver_gear");


        private Detector detector;
    }
}
